#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y;
        scanf("%lld %lld", &X, &Y);
        if (X < Y) printf("REPAIR\n");
        else if (X > Y) printf("NEW PHONE\n");
        else printf("ANY\n");
    }
    return 0;
}

