import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        x = int(data[idx]); y = int(data[idx+1]); idx += 2
        if x < y:
            out.append('REPAIR')
        elif x > y:
            out.append('NEW PHONE')
        else:
            out.append('ANY')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

